function candidate(value) {
  const source = String(value);

  function cleanPath(path) {
    const absolute = path.startsWith("/");
    const parts = path.split("/");
    const kept = [];

    for (const part of parts) {
      if (part === "" || part === ".") {
        continue;
      }
      if (part === "..") {
        if (kept.length && kept[kept.length - 1] !== "..") {
          kept.pop();
        } else if (!absolute) {
          kept.push("..");
        }
      } else {
        kept.push(part);
      }
    }

    if (absolute) {
      return kept.length ? "/" + kept.join("/") : "/";
    }
    return kept.length ? kept.join("/") : ".";
  }

  const urlMatch = source.match(/^([A-Za-z][A-Za-z0-9+.-]*:)(\/\/[^/?#]*)?([^?#]*)(\?[^#]*)?(#.*)?$/);

  if (urlMatch && (urlMatch[2] || source.indexOf(":") !== -1)) {
    const scheme = urlMatch[1];
    const authority = urlMatch[2] || "";
    const path = urlMatch[3] || "";
    const query = urlMatch[4] || "";
    const fragment = urlMatch[5] || "";

    if (path === "") {
      return source;
    }

    return scheme + authority + cleanPath(path) + query + fragment;
  }

  return cleanPath(source);
}
